   116  func newGenerics(s *apiextensions.JSONSchemaProps) (*Generic, error) {
   117          if s == nil {
   118                  return nil, nil
   119          }
   120          g := &Generic{
   121                  Type:        s.Type,
   122                  Description: s.Description,
   123                  Title:       s.Title,
   124                  Nullable:    s.Nullable,
   125          }
   126          if s.Default != nil {
   127                  g.Default = JSON{interface{}(*s.Default)}
   128          }
   129
   130          return g, nil
   131  }
