   133  func newValueValidation(s *apiextensions.JSONSchemaProps) (*ValueValidation, error) {
   134          if s == nil {
   135                  return nil, nil
   136          }
   137          not, err := newNestedValueValidation(s.Not)
   138          if err != nil {
   139                  return nil, err
   140          }
   141          v := &ValueValidation{
   142                  Format:           s.Format,
   143                  Maximum:          s.Maximum,
   144                  ExclusiveMaximum: s.ExclusiveMaximum,
   145                  Minimum:          s.Minimum,
   146                  ExclusiveMinimum: s.ExclusiveMinimum,
   147                  MaxLength:        s.MaxLength,
   148                  MinLength:        s.MinLength,
   149                  Pattern:          s.Pattern,
   150                  MaxItems:         s.MaxItems,
   151                  MinItems:         s.MinItems,
   152                  UniqueItems:      s.UniqueItems,
   153                  MultipleOf:       s.MultipleOf,
   154                  MaxProperties:    s.MaxProperties,
   155                  MinProperties:    s.MinProperties,
   156                  Required:         s.Required,
   157                  Not:              not,
   158          }
   159
   160          for _, e := range s.Enum {
   161                  v.Enum = append(v.Enum, JSON{e})
   162          }
   163
   164          for _, x := range s.AllOf {
   165                  clause, err := newNestedValueValidation(&x)
   166                  if err != nil {
   167                          return nil, err
   168                  }
   169                  v.AllOf = append(v.AllOf, *clause)
   170          }
   171
   172          for _, x := range s.AnyOf {
   173                  clause, err := newNestedValueValidation(&x)
   174                  if err != nil {
   175                          return nil, err
   176                  }
   177                  v.AnyOf = append(v.AnyOf, *clause)
   178          }
   179
   180          for _, x := range s.OneOf {
   181                  clause, err := newNestedValueValidation(&x)
   182                  if err != nil {
   183                          return nil, err
   184                  }
   185                  v.OneOf = append(v.OneOf, *clause)
   186          }
   187
   188          return v, nil
   189  }
