   264  func newExtensions(s *apiextensions.JSONSchemaProps) (*Extensions, error) {
   265          if s == nil {
   266                  return nil, nil
   267          }
   268
   269          ret := &Extensions{
   270                  XEmbeddedResource: s.XEmbeddedResource,
   271                  XIntOrString:      s.XIntOrString,
   272                  XListMapKeys:      s.XListMapKeys,
   273                  XListType:         s.XListType,
   274                  XMapType:          s.XMapType,
   275          }
   276
   277          if s.XPreserveUnknownFields != nil {
   278                  if !*s.XPreserveUnknownFields {
   279                          return nil, fmt.Errorf("internal error: 'x-kubernetes-preserve-unknown-fields' must be true or undefined")
   280                  }
   281                  ret.XPreserveUnknownFields = true
   282          }
   283
   284          return ret, nil
   285  }
   286
   287  func newValidationExtensions(s *apiextensions.JSONSchemaProps) (*ValidationExtensions, error) {
   288          if s == nil {
   289                  return nil, nil
   290          }
   291
   292          ret := &ValidationExtensions{}
   293          if err := apiextensionsv1.Convert_apiextensions_ValidationRules_To_v1_ValidationRules(&s.XValidations, &ret.XValidations, nil); err != nil {
   294                  return nil, err
   295          }
   296
   297          return ret, nil
   298  }
