   300  // validateUnsupportedFields checks that those fields rejected by validation are actually unset.
   301  func validateUnsupportedFields(s *apiextensions.JSONSchemaProps) error {
   302          if len(s.ID) > 0 {
   303                  return fmt.Errorf("OpenAPIV3Schema 'id' is not supported")
   304          }
   305          if len(s.Schema) > 0 {
   306                  return fmt.Errorf("OpenAPIV3Schema 'schema' is not supported")
   307          }
   308          if s.Ref != nil && len(*s.Ref) > 0 {
   309                  return fmt.Errorf("OpenAPIV3Schema '$ref' is not supported")
   310          }
   311          if len(s.PatternProperties) > 0 {
   312                  return fmt.Errorf("OpenAPIV3Schema 'patternProperties' is not supported")
   313          }
   314          if len(s.Dependencies) > 0 {
   315                  return fmt.Errorf("OpenAPIV3Schema 'dependencies' is not supported")
   316          }
   317          if s.AdditionalItems != nil {
   318                  return fmt.Errorf("OpenAPIV3Schema 'additionalItems' is not supported")
   319          }
   320          if len(s.Definitions) > 0 {
   321                  return fmt.Errorf("OpenAPIV3Schema 'definitions' is not supported")
   322          }
   323
   324          return nil
   325  }

