   123  func mergeSpecV3(dest, source *spec3.OpenAPI) error {
   124          if source == nil || source.Paths == nil {
   125                  return nil
   126          }
   127          if dest.Paths == nil {
   128                  dest.Paths = &spec3.Paths{}
   129          }
