352  func (s *Validator) validateExpressions(ctx context.Context, fldPath *field.Path, obj, oldObj interface{}, correlation ratchetingOptions, costBudget int64) (errs field.ErrorList, remainingBudget int64) {
   353          sts := s.Schema
   354
   355          // guard against oldObj being a non-nil interface with a nil value
   356          if oldObj != nil {
   357                  v := reflect.ValueOf(oldObj)
   358                  switch v.Kind() {
   359                  case reflect.Map, reflect.Pointer, reflect.Interface, reflect.Slice:
   360                          if v.IsNil() {
   361                                  oldObj = nil // +k8s:verify-mutation:reason=clone
   362                          }
   363                  }
   364          }
   365
   366          remainingBudget = costBudget
   367          if obj == nil {
   368                  // We only validate non-null values. Rules that need to check for the state of a nullable value or the presence of an optional
   369                  // field must do so from the surrounding schema. E.g. if an array has nullable string items, a rule on the array
   370                  // schema can check if items are null, but a rule on the nullable string schema only validates the non-null strings.
   371                  return nil, remainingBudget
   372          }
   373          if s.compilationErr != nil {
   374                  errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("rule compiler initialization error: %v", s.compilationErr)))
   375                  return errs, remainingBudget
   376          }
   377          if len(s.compiledRules) == 0 {
   378                  return nil, remainingBudget // nothing to do
   379          }
   380          if remainingBudget <= 0 {
   381                  errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("validation failed due to running out of cost budget, no further validation rules will be run")))
   382                  return errs, -1
   383          }
   384          if s.isResourceRoot {
   385                  sts = model.WithTypeAndObjectMeta(sts)
   386          }
   387          activation, optionalOldSelfActivation := s.celActivationFactory(sts, obj, oldObj)
   388          for i, compiled := range s.compiledRules {
   389                  rule := s.uncompiledRules[i]
   390                  if compiled.Error != nil {
   391                          errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("rule compile error: %v", compiled.Error)))
   392                          continue
   393                  }
   394                  if compiled.Program == nil {
   395                          // rule is empty
   396                          continue
   397                  }
   398
   399                  // If ratcheting is enabled, allow rule with oldSelf to evaluate
   400                  // when `optionalOldSelf` is set to true
   401                  optionalOldSelfRule := ptr.Deref(rule.OptionalOldSelf, false)
   402                  if compiled.UsesOldSelf && oldObj == nil {
   403                          // transition rules are evaluated only if there is a comparable existing value
   404                          // But if the rule uses optional oldSelf and gate is enabled we allow
   405                          // the rule to be evaluated
   406                          if !utilfeature.DefaultFeatureGate.Enabled(features.CRDValidationRatcheting) {
   407                                  continue
   408                          }
   409
   410                          if !optionalOldSelfRule {
   411                                  continue
   412                          }
   413                  }
   414
   415                  ruleActivation := activation
   416                  if optionalOldSelfRule {
   417                          ruleActivation = optionalOldSelfActivation
   418                  }
   419
   420                  evalResult, evalDetails, err := compiled.Program.ContextEval(ctx, ruleActivation)
   421                  if evalDetails == nil {
   422                          errs = append(errs, field.InternalError(fldPath, fmt.Errorf("runtime cost could not be calculated for validation rule: %v, no further validation rules will be run", ruleErrorString(rule))))
   423                          return errs, -1
   424                  } else {
   425                          rtCost := evalDetails.ActualCost()
   426                          if rtCost == nil {
   427                                  errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("runtime cost could not be calculated for validation rule: %v, no further validation rules will be run", ruleErrorString(rule))))
   428                                  return errs, -1
   429                          } else {
   430                                  if *rtCost > math.MaxInt64 || int64(*rtCost) > remainingBudget {
   431                                          errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("validation failed due to running out of cost budget, no further validation rules will be run")))
   432                                          return errs, -1
   433                                  }
   434                                  remainingBudget -= int64(*rtCost)
   435                          }
   436                  }
   437                  if err != nil {
   438                          // see types.Err for list of well defined error types
   439                          if strings.HasPrefix(err.Error(), "no such overload") {
   440                                  // Most overload errors are caught by the compiler, which provides details on where exactly in the rule
   441                                  // error was found. Here, an overload error has occurred at runtime no details are provided, so we
   442                                  // append a more descriptive error message. This error can only occur when static type checking has
   443                                  // been bypassed. int-or-string is typed as dynamic and so bypasses compiler type checking.
   444                                  errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("'%v': call arguments did not match a supported operator, function or macro signature for rule: %v", err, ruleErrorString(rule))))
   445                          } else if strings.HasPrefix(err.Error(), "operation cancelled: actual cost limit exceeded") {
   446                                  errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("'%v': no further validation rules will be run due to call cost exceeds limit for rule: %v", err, ruleErrorString(rule))))
   447                                  return errs, -1
   448                          } else {
   449                                  // no such key: {key}, index out of bounds: {index}, integer overflow, division by zero, ...
   450                                  errs = append(errs, field.Invalid(fldPath, sts.Type, fmt.Sprintf("%v evaluating rule: %v", err, ruleErrorString(rule))))
   451                          }
   452                          continue
   453                  }
   454                  if evalResult != types.True {
   455                          currentFldPath := fldPath
   456                          if len(compiled.NormalizedRuleFieldPath) > 0 {
   457                                  currentFldPath = currentFldPath.Child(compiled.NormalizedRuleFieldPath)
   458                          }
   459
   460                          addErr := func(e *field.Error) {
   461                                  if !compiled.UsesOldSelf && correlation.shouldRatchetError() {
   462                                          warning.AddWarning(ctx, "", e.Error())
   463                                  } else {
   464                                          errs = append(errs, e)
   465                                  }
   466                          }
   467
   468                          if compiled.MessageExpression != nil {
   469                                  messageExpression, newRemainingBudget, msgErr := evalMessageExpression(ctx, compiled.MessageExpression, rule.MessageExpression, activation, remainingBudget)
   470                                  if msgErr != nil {
   471                                          if msgErr.Type == cel.ErrorTypeInternal {
   472                                                  addErr(field.InternalError(currentFldPath, msgErr))
   473                                                  return errs, -1
   474                                          } else if msgErr.Type == cel.ErrorTypeInvalid {
   475                                                  addErr(field.Invalid(currentFldPath, sts.Type, msgErr.Error()))
   476                                                  return errs, -1
   477                                          } else {
   478                                                  klog.V(2).ErrorS(msgErr, "messageExpression evaluation failed")
   479                                                  addErr(fieldErrorForReason(currentFldPath, sts.Type, ruleMessageOrDefault(rule), rule.Reason))
   480                                                  remainingBudget = newRemainingBudget
   481                                          }
   482                                  } else {
   483                                          addErr(fieldErrorForReason(currentFldPath, sts.Type, messageExpression, rule.Reason))
   484                                          remainingBudget = newRemainingBudget
   485                                  }
   486                          } else {
   487                                  addErr(fieldErrorForReason(currentFldPath, sts.Type, ruleMessageOrDefault(rule), rule.Reason))
   488                          }
   489                  }
   490          }
   491          return errs, remainingBudget
   492  }
