95  func validator(validationSchema, nodeSchema *schema.Structural, isResourceRoot bool, declType *cel.DeclType, perCallLimit uint64) *Validator {
    96          compilationSchema := *nodeSchema
    97          compilationSchema.XValidations = validationSchema.XValidations
    98          compiledRules, err := Compile(&compilationSchema, declType, perCallLimit, environment.MustBaseEnvSet(environment.DefaultCompatibilityVersion(), true), StoredExpressionsEnvLoader())
    99
   100          var itemsValidator, additionalPropertiesValidator *Validator
   101          var propertiesValidators map[string]Validator
   102          var allOfValidators []*Validator
   103          var elemType *cel.DeclType
   104          if declType != nil {
   105                  elemType = declType.ElemType
   106          } else {
   107                  elemType = declType
   108          }
   109
   110          if validationSchema.Items != nil && nodeSchema.Items != nil {
   111                  itemsValidator = validator(validationSchema.Items, nodeSchema.Items, nodeSchema.Items.XEmbeddedResource, elemType, perCallLimit)
   112          }
   113
   114          if len(validationSchema.Properties) > 0 {
   115                  propertiesValidators = make(map[string]Validator, len(validationSchema.Properties))
   116                  for k, validationProperty := range validationSchema.Properties {
   117                          nodeProperty, ok := nodeSchema.Properties[k]
   118                          if !ok {
   119                                  // Can only add value validations for fields that are on the
   120                                  // structural spine of the schema.
   121                                  continue
   122                          }
   123
   124                          var fieldType *cel.DeclType
   125                          if escapedPropName, ok := cel.Escape(k); ok {
   126                                  if declType == nil {
   127                                          continue
   128                                  }
   129                                  if f, ok := declType.Fields[escapedPropName]; ok {
   130                                          fieldType = f.Type
   131                                  } else {
   132                                          // fields with unknown types are omitted from CEL validation entirely
   133                                          continue
   134                                  }
   135                          } else {
   136                                  // field may be absent from declType if the property name is unescapable, in which case we should convert
   137                                  // the field value type to a DeclType.
   138                                  fieldType = model.SchemaDeclType(&nodeProperty, nodeProperty.XEmbeddedResource)
   139                                  if fieldType == nil {
   140                                          continue
   141                                  }
   142                          }
   143                          if p := validator(&validationProperty, &nodeProperty, nodeProperty.XEmbeddedResource, fieldType, perCallLimit); p != nil {
   144                                  propertiesValidators[k] = *p
   145                          }
   146                  }
   147          }
   148          if validationSchema.AdditionalProperties != nil && validationSchema.AdditionalProperties.Structural != nil &&
   149                  nodeSchema.AdditionalProperties != nil && nodeSchema.AdditionalProperties.Structural != nil {
   150                  additionalPropertiesValidator = validator(validationSchema.AdditionalProperties.Structural, nodeSchema.AdditionalProperties.Structural, nodeSchema.AdditionalProperties.Structural.XEmbeddedResource, elemType, perCallLimit)
   151          }
   152
   153          if validationSchema.ValueValidation != nil && len(validationSchema.ValueValidation.AllOf) > 0 {
   154                  allOfValidators = make([]*Validator, 0, len(validationSchema.ValueValidation.AllOf))
   155                  for _, allOf := range validationSchema.ValueValidation.AllOf {
   156                          allOfValidator := validator(nestedToStructural(&allOf), nodeSchema, isResourceRoot, declType, perCallLimit)
   157                          if allOfValidator != nil {
   158                                  allOfValidators = append(allOfValidators, allOfValidator)
   159                          }
   160                  }
   161          }
   162
   163          if len(compiledRules) > 0 || err != nil || itemsValidator != nil || additionalPropertiesValidator != nil || len(propertiesValidators) > 0 || len(allOfValidators) > 0 {
   164                  activationFactory := validationActivationWithoutOldSelf
   165                  for _, rule := range compiledRules {
   166                          if rule.UsesOldSelf {
   167                                  activationFactory = validationActivationWithOldSelf
   168                                  break
   169                          }
   170                  }
   171
   172                  return &Validator{
   173                          compiledRules:        compiledRules,
   174                          uncompiledRules:      validationSchema.XValidations,
   175                          compilationErr:       err,
   176                          isResourceRoot:       isResourceRoot,
   177                          Items:                itemsValidator,
   178                          AdditionalProperties: additionalPropertiesValidator,
   179                          Properties:           propertiesValidators,
   180                          AllOfValidators:      allOfValidators,
   181                          celActivationFactory: activationFactory,
   182                          Schema:               nodeSchema,
   183                  }
   184          }
   185
   186          return nil
   187  }
