545  func ValidFieldPath(jsonPath string, schema *schema.Structural, options ...ValidFieldPathOption) (validFieldPath *field.Path, foundSchema *schema.Structural, err error) {
   546          opts := &validFieldPathOptions{allowArrayNotation: true}
   547          for _, opt := range options {
   548                  opt(opts)
   549          }
   550
   551          appendToPath := func(name string, isNamed bool) error {
   552                  if !isNamed {
   553                          validFieldPath = validFieldPath.Key(name)
   554                          schema = schema.AdditionalProperties.Structural
   555                  } else {
   556                          validFieldPath = validFieldPath.Child(name)
   557                          val, ok := schema.Properties[name]
   558                          if !ok {
   559                                  return fmt.Errorf("does not refer to a valid field")
   560                          }
   561                          schema = &val
   562                  }
   563                  return nil
   564          }
   565
   566          validFieldPath = nil
   567
   568          scanner := bufio.NewScanner(strings.NewReader(jsonPath))
   569
   570          // configure the scanner to split the string into tokens.
   571          // The three delimiters ('.', '[', ']') will be returned as single char tokens.
   572          // All other text between delimiters is returned as string tokens.
   573          scanner.Split(func(data []byte, atEOF bool) (advance int, token []byte, err error) {
   574                  if len(data) > 0 {
   575                          for i := 0; i < len(data); i++ {
   576                                  // If in a single quoted string, look for the end of string
   577                                  // ignoring delimiters.
   578                                  if data[0] == '\'' {
   579                                          if i > 0 && data[i] == '\'' && data[i-1] != '\\' {
   580                                                  // Return quoted string
   581                                                  return i + 1, data[:i+1], nil
   582                                          }
   583                                          continue
   584                                  }
   585                                  switch data[i] {
   586                                  case '.', '[', ']': // delimiters
   587                                          if i == 0 {
   588                                                  // Return the delimiter.
   589                                                  return 1, data[:1], nil
   590                                          } else {
   591                                                  // Return identifier leading up to the delimiter.
   592                                                  // The next call to split will return the delimiter.
   593                                                  return i, data[:i], nil
   594                                          }
   595                                  }
   596                          }
   597                          if atEOF {
   598                                  // Return the string.
   599                                  return len(data), data, nil
   600                          }
   601                  }
   602                  return 0, nil, nil
   603          })
   604
   605          var tok string
   606          var isNamed bool
   607          for scanner.Scan() {
   608                  tok = scanner.Text()
   609                  switch tok {
   610                  case "[":
   611                          if !opts.allowArrayNotation {
   612                                  return nil, nil, fmt.Errorf("array notation is not allowed")
   613                          }
   614                          if !scanner.Scan() {
   615                                  return nil, nil, fmt.Errorf("unexpected end of JSON path")
   616                          }
   617                          tok = scanner.Text()
   618                          if len(tok) < 2 || tok[0] != '\'' || tok[len(tok)-1] != '\'' {
   619                                  return nil, nil, fmt.Errorf("expected single quoted string but got %s", tok)
   620                          }
   621                          unescaped, err := unescapeSingleQuote(tok[1 : len(tok)-1])
   622                          if err != nil {
   623                                  return nil, nil, fmt.Errorf("invalid string literal: %w", err)
   624                          }
   625
   626                          if schema.Properties != nil {
   627                                  isNamed = true
   628                          } else if schema.AdditionalProperties != nil {
   629                                  isNamed = false
   630                          } else {
   631                                  return nil, nil, fmt.Errorf("does not refer to a valid field")
   632                          }
   633                          if err := appendToPath(unescaped, isNamed); err != nil {
   634                                  return nil, nil, err
   635                          }
   636                          if !scanner.Scan() {
   637                                  return nil, nil, fmt.Errorf("unexpected end of JSON path")
   638                          }
   639                          tok = scanner.Text()
   640                          if tok != "]" {
   641                                  return nil, nil, fmt.Errorf("expected ] but got %s", tok)
   642                          }
   643                  case ".":
   644                          if !scanner.Scan() {
   645                                  return nil, nil, fmt.Errorf("unexpected end of JSON path")
   646                          }
   647                          tok = scanner.Text()
   648                          if schema.Properties != nil {
   649                                  isNamed = true
   650                          } else if schema.AdditionalProperties != nil {
   651                                  isNamed = false
   652                          } else {
   653                                  return nil, nil, fmt.Errorf("does not refer to a valid field")
   654                          }
   655                          if err := appendToPath(tok, isNamed); err != nil {
   656                                  return nil, nil, err
   657                          }
   658                  default:
   659                          return nil, nil, fmt.Errorf("expected [ or . but got: %s", tok)
   660                  }
   661          }
   662
   663          return validFieldPath, schema, nil
   664  }
