684  func evalMessageExpression(ctx context.Context, expr celgo.Program, exprSrc string, activation interpreter.Activation, remainingBudget int64) (string, int64, *cel.Error) {
   685          evalResult, evalDetails, err := expr.ContextEval(ctx, activation)
   686          if evalDetails == nil {
   687                  return "", -1, &cel.Error{
   688                          Type:   cel.ErrorTypeInternal,
   689                          Detail: fmt.Sprintf("runtime cost could not be calculated for messageExpression: %q", exprSrc),
   690                  }
   691          }
   692          rtCost := evalDetails.ActualCost()
   693          if rtCost == nil {
   694                  return "", -1, &cel.Error{
   695                          Type:   cel.ErrorTypeInternal,
   696                          Detail: fmt.Sprintf("runtime cost could not be calculated for messageExpression: %q", exprSrc),
   697                  }
   698          } else if *rtCost > math.MaxInt64 || int64(*rtCost) > remainingBudget {
   699                  return "", -1, &cel.Error{
   700                          Type:   cel.ErrorTypeInvalid,
   701                          Detail: "messageExpression evaluation failed due to running out of cost budget, no further validation rules will be run",
   702                  }
   703          }
   704          if err != nil {
   705                  if strings.HasPrefix(err.Error(), "operation cancelled: actual cost limit exceeded") {
   706                          return "", -1, &cel.Error{
   707                                  Type:   cel.ErrorTypeInvalid,
   708                                  Detail: fmt.Sprintf("no further validation rules will be run due to call cost exceeds limit for messageExpression: %q", exprSrc),
   709                          }
   710                  }
   711                  return "", remainingBudget - int64(*rtCost), &cel.Error{
   712                          Detail: fmt.Sprintf("messageExpression evaluation failed due to: %v", err.Error()),
   713                  }
   714          }
   715          messageStr, ok := evalResult.Value().(string)
   716          if !ok {
   717                  return "", remainingBudget - int64(*rtCost), &cel.Error{
   718                          Detail: "messageExpression failed to convert to string",
   719                  }
   720          }
   721          trimmedMsgStr := strings.TrimSpace(messageStr)
   722          if len(trimmedMsgStr) > celconfig.MaxEvaluatedMessageExpressionSizeBytes {
   723                  return "", remainingBudget - int64(*rtCost), &cel.Error{
   724                          Detail: fmt.Sprintf("messageExpression beyond allowable length of %d", celconfig.MaxEvaluatedMessageExpressionSizeBytes),
   725                  }
   726          } else if hasNewlines(trimmedMsgStr) {
   727                  return "", remainingBudget - int64(*rtCost), &cel.Error{
   728                          Detail: "messageExpression should not contain line breaks",
   729                  }
   730          } else if len(trimmedMsgStr) == 0 {
   731                  return "", remainingBudget - int64(*rtCost), &cel.Error{
   732                          Detail: "messageExpression should evaluate to a non-empty string",
   733                  }
   734          }
   735          return trimmedMsgStr, remainingBudget - int64(*rtCost), nil
   736  }
