   214  // ratchetingOptions stores the current correlation object and the nearest
   215  // parent which was correlatable. The parent is stored so that we can check at
   216  // the point an error is thrown whether it should be ratcheted using simple
   217  // logic
   218  // Key and Index should be used as normally to traverse to the next node.
   219  type ratchetingOptions struct {
   220          // Current correlation object. If nil, then this node is from an uncorrelatable
   221          // part of the schema
   222          currentCorrelation *common.CorrelatedObject
   223
   224          // If currentCorrelation is nil, this is the nearest parent to this node
   225          // which was correlatable. If the parent is deepequal to its old value,
   226          // then errors thrown by this node are ratcheted
   227          nearestParentCorrelation *common.CorrelatedObject
   228  }
   229
   230  // shouldRatchetError returns true if the errors raised by the current node
   231  // should be ratcheted.
   232  //
   233  // Errors for the current node should be ratcheted if one of the following is true:
   234  //  1. The current node is correlatable, and it is equal to its old value
   235  //  2. The current node has a correlatable ancestor, and the ancestor is equal
   236  //     to its old value.
   237  func (r ratchetingOptions) shouldRatchetError() bool {
   238          if r.currentCorrelation != nil {
   239                  return r.currentCorrelation.CachedDeepEqual()
   240          }
   241
   242          return r.nearestParentCorrelation.CachedDeepEqual()
   243  }
   244
   245  // Finds the next node following the field in the tree and returns options using
   246  // that node. If none could be found, then retains a reference to the last
   247  // correlatable ancestor for ratcheting purposes
   248  func (r ratchetingOptions) key(field string) ratchetingOptions {
   249          if r.currentCorrelation == nil {
   250                  return r
   251          } else if r.nearestParentCorrelation == nil && (field == "apiVersion" || field == "kind") {
   252                  // We cannot ratchet changes to the APIVersion and kind fields field since
   253                  // they aren't visible. (both old and new are converted to the same type)
   254                  //
   255                  return ratchetingOptions{}
   256          }
   257
   258          // nearestParentCorrelation is always non-nil except for the root node.
   259          // The below line ensures that the next nearestParentCorrelation is set
   260          // to a non-nil r.currentCorrelation
   261          return ratchetingOptions{currentCorrelation: r.currentCorrelation.Key(field), nearestParentCorrelation: r.currentCorrelation}
   262  }
   263
   264  // Finds the next node following the index in the tree and returns options using
   265  // that node. If none could be found, then retains a reference to the last
   266  // correlatable ancestor for ratcheting purposes
   267  func (r ratchetingOptions) index(idx int) ratchetingOptions {
   268          if r.currentCorrelation == nil {
   269                  return r
   270          }
   271
   272          return ratchetingOptions{currentCorrelation: r.currentCorrelation.Index(idx), nearestParentCorrelation: r.currentCorrelation}
   273  }
